// Preparar dados para o AI Agent
const items = $input.all();

// Separar pendentes (input 1) e contexto (input 2)
// O Merge combineAll junta tudo - precisamos reconstruir
const loopData = $node['Loop por mentorado'].json;
const mentoradoNome = loopData.mentorado_nome;
const mentoradoId = loopData.mentorado_id;

const pendentesRaw = $node['Buscar msgs pendentes'].json;
const contextoRaw = $node['Buscar contexto conversa'].json;

// Formatar pendentes como lista
const pendentesArr = Array.isArray(pendentesRaw) ? pendentesRaw : [pendentesRaw];
const contextoArr = Array.isArray(contextoRaw) ? contextoRaw : [contextoRaw];

const pendentesText = pendentesArr
  .filter(p => p && p.id)
  .map(p => `[ID: ${p.id}] ${p.sender_name} (${p.message_type}) em ${p.created_at}: "${p.conteudo}"`)
  .join('\n');

const contextoText = contextoArr
  .filter(c => c && c.conteudo)
  .reverse()
  .map(c => {
    const role = c.eh_equipe ? '[EQUIPE]' : '[MENTORADO]';
    return `${role} ${c.sender_name} (${c.created_at}): "${c.conteudo}"`;
  })
  .join('\n');

return [{
  json: {
    mentorado_id: mentoradoId,
    mentorado_nome: mentoradoNome,
    prompt: `MENTORADO: ${mentoradoNome}\n\nMENSAGENS PENDENTES DE RESPOSTA (analise cada uma):\n${pendentesText}\n\nCONTEXTO DA CONVERSA (ordem cronologica, mais antigas primeiro):\n${contextoText}`
  }
}];

// Parsear resposta da IA e extrair IDs para update
const aiResponse = $input.first().json.output || $input.first().json.text || '';

let parsed;
try {
  // Tentar extrair JSON da resposta (pode ter texto antes/depois)
  const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
  if (!jsonMatch) {
    return [{ json: { ids_to_update: [], error: 'No JSON found in AI response', raw: aiResponse } }];
  }
  parsed = JSON.parse(jsonMatch[0]);
} catch (e) {
  return [{ json: { ids_to_update: [], error: 'JSON parse error: ' + e.message, raw: aiResponse } }];
}

// Combinar respondidas + nao_requerem_resposta
const respondidas = Array.isArray(parsed.respondidas) ? parsed.respondidas : [];
const naoRequerem = Array.isArray(parsed.nao_requerem_resposta) ? parsed.nao_requerem_resposta : [];
const allIds = [...new Set([...respondidas, ...naoRequerem])].filter(id => typeof id === 'number' && id > 0);

if (allIds.length === 0) {
  return [{ json: { ids_to_update: [], motivo: parsed.motivo || 'nenhuma respondida', skip_update: true } }];
}

return [{
  json: {
    ids_to_update: allIds,
    ids_respondidas: respondidas,
    ids_nao_requerem: naoRequerem,
    motivo: parsed.motivo || '',
    mentorado_id: $node['Preparar prompt para IA'].json.mentorado_id,
    mentorado_nome: $node['Preparar prompt para IA'].json.mentorado_nome,
    total_marcadas: allIds.length,
    skip_update: false
  }
}];

// Log da execução
const data = $node['Parsear resposta IA'].json;
const updated = $node['Marcar como respondidas'].json;

return [{
  json: {
    mentorado: data.mentorado_nome,
    respondidas: data.ids_respondidas?.length || 0,
    nao_requerem: data.ids_nao_requerem?.length || 0,
    total_marcadas: data.total_marcadas || 0,
    motivo: data.motivo,
    timestamp: new Date().toISOString()
  }
}];
